def get_distance(v1, v2):
    return math.sqrt((v1.x - v2.x)**2 + (v1.y - v2.y)**2)

def lerp_vec2(v1, v2, t):
    return rl.Vector2(v1.x + (v2.x - v1.x) * t, v1.y + (v2.y - v1.y) * t)

