    def __init__(self):
        self.particles = []

    def emit(self, pos, color, count=10):
        for _ in range(count):
            self.particles.append({
                "pos": rl.Vector2(pos.x, pos.y),
                "vel": rl.Vector2(random.uniform(-2, 2), random.uniform(-2, 2)),
                "life": 1.0,
                "color": color
            })

    def update(self, dt):
