        rl.draw_rectangle_v(rl.Vector2(self.pos.x - 15, self.pos.y - 15), rl.Vector2(30, 30), self.color)
        rl.draw_circle_lines(int(self.pos.x), int(self.pos.y), self.range, rl.fade(self.color, 0.2))"
